/** A cell's position on the infinite grid as [x, y] coordinates. */
export type Cell = [number, number];

type CellKey = string;

const toKey = ([x, y]: Cell): CellKey => `${x},${y}`;

const fromKey = (key: CellKey): Cell => {
  const [x, y] = key.split(",");
  return [Number(x), Number(y)];
};

/**
 * Computes the next generation of Conway's Game of Life from the
 * given set of currently live cells, returning the cells that are
 * alive in the following tick.
 */
export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(toKey));
  const neighborCounts = countNeighbors(liveCells);

  const survives = (key: CellKey, count: number) =>
    liveKeys.has(key) && (count === 2 || count === 3);
  const isBorn = (key: CellKey, count: number) =>
    !liveKeys.has(key) && count === 3;

  const next: Cell[] = [];
  for (const [key, count] of neighborCounts) {
    if (survives(key, count) || isBorn(key, count)) {
      next.push(fromKey(key));
    }
  }
  return next;
}

function countNeighbors(liveCells: Cell[]): Map<CellKey, number> {
  const counts = new Map<CellKey, number>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = toKey([x + dx, y + dy]);
        counts.set(key, (counts.get(key) ?? 0) + 1);
      }
    }
  }
  return counts;
}
